import {
  Typography,
  makeStyles,
  Box,
  IconButton,
  Menu,
  MenuItem,
} from '@material-ui/core';
import MoreVertIcon from '@material-ui/icons/MoreVert';
import { useEffect, useMemo, useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { useRouteRef } from '@backstage/core-plugin-api';
import { usePermission } from '@backstage/plugin-permission-react';
import { catalogEntityCreatePermission } from '@backstage/plugin-catalog-common/alpha';
import {
  CatalogFilterLayout,
  EntityKindPicker,
  EntityListProvider,
  EntitySearchBar,
  UserListPicker,
  useEntityList,
  EntityTypeFilter,
  EntityTagFilter,
} from '@backstage/plugin-catalog-react';
import { TemplateGroups } from '@backstage/plugin-scaffolder-react/alpha';
import { WizardCard } from '../Home/TemplateCard';
import { TemplateEntityV1beta3 } from '@backstage/plugin-scaffolder-common';
import { rootRouteRef } from '../../routes';
import { TagFilterPicker } from '../utils/TagFilterPicker';

const useStyles = makeStyles(theme => ({
  headerRow: {
    display: 'flex',
    justifyContent: 'space-between',
    alignItems: 'flex-start',
    marginBottom: '16px',
  },
  description: {
    color: theme.palette.text.secondary,
    fontSize: 16,
    lineHeight: 1.6,
    flex: 1,
  },
  layoutContainer: {
    borderRadius: theme.shape.borderRadius,
    border: `1px solid ${theme.palette.divider}`,
    padding: theme.spacing(2),
    backgroundColor: theme.palette.background.paper,
  },
}));

const ProjectTagPicker = () => {
  const { backendEntities, filters, updateFilters } = useEntityList();
  const selectedTags = (filters.tags as EntityTagFilter)?.values ?? [];

  const availableTags = useMemo(() => {
    const tagSet = new Set<string>();
    for (const entity of backendEntities) {
      const templateEntity = entity as TemplateEntityV1beta3;
      if (templateEntity.spec?.type?.includes('project')) {
        for (const tag of entity.metadata?.tags || []) {
          tagSet.add(tag);
        }
      }
    }
    return Array.from(tagSet).sort((a, b) => a.localeCompare(b));
  }, [backendEntities]);

  const handleTagChange = (newValue: string[]) => {
    updateFilters({
      ...filters,
      tags: newValue.length > 0 ? new EntityTagFilter(newValue) : undefined,
    });
  };

  if (availableTags.length === 0) {
    return null;
  }

  return (
    <TagFilterPicker
      label="Tags"
      options={availableTags}
      value={selectedTags}
      onChange={handleTagChange}
    />
  );
};

const ProjectTypeFilter = () => {
  const { filters, updateFilters } = useEntityList();

  useEffect(() => {
    if (!filters.type) {
      updateFilters({
        ...filters,
        type: new EntityTypeFilter(['project']),
      });
    }
  }, [filters, updateFilters]);

  return null;
};

export const CreateProjectContent = () => {
  const classes = useStyles();
  const navigate = useNavigate();
  const rootLink = useRouteRef(rootRouteRef);
  const { allowed } = usePermission({
    permission: catalogEntityCreatePermission,
  });
  const [menuAnchorEl, setMenuAnchorEl] = useState<null | HTMLElement>(null);
  const menuOpen = Boolean(menuAnchorEl);

  const handleMenuOpen = (event: React.MouseEvent<HTMLElement>) => {
    setMenuAnchorEl(event.currentTarget);
  };

  const handleMenuClose = () => {
    setMenuAnchorEl(null);
  };

  const handleAddTemplate = () => {
    handleMenuClose();
    navigate(`${rootLink()}/catalog-import`);
  };

  return (
    <div>
      <Box className={classes.headerRow}>
        <Typography variant="body1" className={classes.description}>
          Create a new Ansible automation project from a template. Choose a
          starting point that matches your use case — playbook projects,
          cloud provisioning, or network automation — then customize the
          details.
        </Typography>
        {allowed && (
          <>
            <IconButton
              aria-label="more options"
              aria-controls="project-create-menu"
              aria-haspopup="true"
              onClick={handleMenuOpen}
            >
              <MoreVertIcon />
            </IconButton>
            <Menu
              id="project-create-menu"
              anchorEl={menuAnchorEl}
              open={menuOpen}
              onClose={handleMenuClose}
              anchorOrigin={{
                vertical: 'bottom',
                horizontal: 'right',
              }}
              transformOrigin={{
                vertical: 'top',
                horizontal: 'right',
              }}
              getContentAnchorEl={null}
              MenuListProps={{ autoFocusItem: false }}
            >
              <MenuItem onClick={handleAddTemplate}>
                Import Template
              </MenuItem>
            </Menu>
          </>
        )}
      </Box>
      <EntityListProvider>
        <ProjectTypeFilter />
        <Box className={classes.layoutContainer}>
          <CatalogFilterLayout>
            <CatalogFilterLayout.Filters>
              <div>
                <EntitySearchBar />
              </div>
              <EntityKindPicker initialFilter="template" hidden />
              <div>
                <UserListPicker
                  initialFilter="all"
                  availableFilters={['all', 'starred']}
                />
              </div>
              <ProjectTagPicker />
            </CatalogFilterLayout.Filters>
            <CatalogFilterLayout.Content>
              <div>
                <TemplateGroups
                  groups={[
                    {
                      filter: (entity: TemplateEntityV1beta3) => {
                        return (
                          entity.spec?.type?.includes('project') ?? false
                        );
                      },
                    },
                  ]}
                  TemplateCardComponent={WizardCard}
                />
              </div>
            </CatalogFilterLayout.Content>
          </CatalogFilterLayout>
        </Box>
      </EntityListProvider>
    </div>
  );
};
